/* com.educare.edu.comn.mapper.AttendStdntMapper.updateByPk */
	update t_attend_stdnt
	set 
		att_cd=#{attCd}
	where
		edu_seq=#{eduSeq} and time_seq=#{timeSeq} and user_id=#{userId}

/* com.educare.edu.comn.mapper.AttendStdntMapper.updateAttCdByPk */
	UPDATE t_attend_stdnt
	SET 
		ATT_CD=#{attCd}
	WHERE
		EDU_SEQ=#{eduSeq} AND TIME_SEQ=#{timeSeq} AND USER_ID=#{userId}
